const cfg = $items("Config")[0].json;
const baseUrl = cfg.baseUrl || "https://op.europa.eu";
const locale = cfg.locale || "en";
const combinedParam = cfg.combinedParam;
const institutionName = cfg.institutionName || "";
const startUrl =
  `${baseUrl}/o/wiw-webservice/sublevels` +
  `?WIW_ORGANIZATION_DETAIL_COMBINED_URL_PARAM=${encodeURIComponent(combinedParam)}` +
  `&WIW_ORGANIZATION_DETAIL_LOCALE_PARAM=${encodeURIComponent(locale)}` +
  `&WIW_URL_TEMPLATE_PARAM=reduced/subleveloforganization/`;
return [{
  json: {
    baseUrl,
    locale,
    combinedParam,
    institutionName,
    startUrl,
    perRequestTimeoutMs: Number(cfg.perRequestTimeoutMs || 40000),
    concurrency: Number(cfg.concurrency || 9),
    institutionType: cfg.institutionType || "",
    institutionPublicUrl: cfg.institutionPublicUrl || ""
  }
}];

async function main() {

function stripHtml(html) {
  return (html || "")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<[^>]*>/g, " ")
    .replace(/&nbsp;|&#160;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, " ")
    .trim();
}

function stripOrgCode(label) {
  return (label || "").replace(/^\s*\[[^\]]+\]\s*/, "").trim();
}

function absolutize(baseUrl, u) {
  if (!u) return "";
  if (/^https?:\/\//i.test(u)) return u;
  if (u.startsWith("//")) return "https:" + u;
  if (u.startsWith("/")) return baseUrl + u;
  return baseUrl + "/" + u;
}

function extractHref(h) {
  const m = (h || "").match(/href\s*=\s*"([^"]+)"/i);
  return m ? m[1] : "";
}

const TITLE_RE = new RegExp(
  '(?:President of the European Commission|Executive Vice-President|Vice-President of the European Commission|' +
  'High Representative for Foreign Affairs and Security Policy|High Representative|Commissioner for|Commissioner|' +
  'Secretary-General|Deputy Secretary-General|Director-General|Deputy Director-General|' +
  'Director of Office|Head of the Private Office|Head of Unit|Head of Office|Head of sector|' +
  'Head of Division|Head of Cabinet|Head of Department|Head of Programme|Head of Task Force|' +
  'Head of Administration|Head of Projects|Head of Strategy|Head of Resource|' +
  'Deputy Head of Unit|Deputy Head of Division|' +
  'Chief Executive Officer|Chief Operating Officer|Chief Financial Officer|' +
  'Chief Risk Officer|Chief Compliance Officer|Chief|' +
  'Managing Director|Deputy Managing Director|' +
  'Principal Legal Adviser|Acting Principal Legal Adviser|Legal Adviser|Principal|Acting|' +
  'Digital Transformation Officer|Acting Director|Acting Head|' +
  'Vice-President|President|Chair of|Chairperson|Chair|' +
  'Senior Adviser|Senior Manager|Senior Officer|Senior Expert|' +
  'Adviser|Advisor|Administrator|Coordinator|Manager|Expert|Director|Officer|' +
  'Deputy Director|Deputy Chair|Deputy|Member of Cabinet|Member|Head' +
  ')\\b', 'i'
);

function parseLabelNames(labelHtml) {
  const text = stripHtml(labelHtml).trim();
  const ph = text.match(/(\+?\d[\d\s\-()]{6,}\d)/);
  const noPhone = text.replace(/(\+?\d[\d\s\-()]{6,}\d)/g, "").trim();
  const noHonorific = noPhone.replace(/\b(Ms|Mr|Mrs|Dr)\.?\s+/gi, "").trim();
  const namePattern = /([A-Z\xC0-\xD6\xD8-\xDE][a-z\xE0-\xFF]+(?:\s+[A-Z\xC0-\xD6\xD8-\xDE][a-z\xE0-\xFF]+)*\s+[A-Z\xC0-\xD6\xD8-\xDE]{2,}(?:\s+[A-Z\xC0-\xD6\xD8-\xDE]{2,})*)/g;
  const matches = [...noHonorific.matchAll(namePattern)];
  if (!matches.length) {
    const m2 = noHonorific.match(TITLE_RE);
    return [{
      labelName: m2 && m2.index > 0 ? noHonorific.slice(0, m2.index).trim() : noHonorific,
      labelTitle: m2 ? noHonorific.slice(m2.index).trim() : "",
      phoneFromLabel: ph ? ph[1].trim() : ""
    }];
  }
  return matches.map((match, i) => {
    const nextMatch = matches[i + 1];
    const titleChunk = nextMatch
      ? noHonorific.slice(match.index + match[0].length, nextMatch.index)
      : noHonorific.slice(match.index + match[0].length);
    return {
      labelName: match[1].trim(),
      labelTitle: titleChunk.trim(),
      phoneFromLabel: ph ? ph[1].trim() : ""
    };
  });
}

async function postOne(url, timeout) {
  try {
    return await helpers.httpRequest({
      method: "POST", url, timeout: timeout || 30000, json: true,
      headers: { "User-Agent": "Mozilla/5.0", "x-requested-with": "XMLHttpRequest", "accept": "*/*" }
    });
  } catch { return null; }
}

const cfg = $input.first().json;
const baseUrl = cfg.baseUrl || "https://op.europa.eu";
const timeoutMs = Number(cfg.perRequestTimeoutMs || 40000);

const seen = {};
const personJobs = [];
let currentLevel = [{ url: cfg.startUrl, selfLabel: "", topLevel: "", depth: 0 }];

while (currentLevel.length > 0) {
  const toFetch = currentLevel.filter(e => e.url && !seen[e.url]);
  toFetch.forEach(e => { seen[e.url] = 1; });
  if (!toFetch.length) break;
  const levelResults = await Promise.all(
    toFetch.map(entry => postOne(entry.url, timeoutMs).then(items => ({ entry, items })))
  );
  const nextLevel = [];
  for (const { entry, items } of levelResults) {
    if (!items) continue;
    for (const it of items) {
      const label = stripOrgCode(stripHtml(it && it.label || ""));
      const thisTop = entry.topLevel || label;
      const nextDepth = entry.depth + 1;
      const looksLikePerson = /\b(Ms|Mr|Mrs|Dr)\b/i.test(label);
      if (it && it.leaf) {
        const href = extractHref(it.label || "");
        if (href) {
          const persons = parseLabelNames(it.label || "");
          for (const p of persons) {
            personJobs.push({
              personUrl: absolutize(baseUrl, href),
              department: entry.selfLabel,
              topLevel: thisTop,
              labelName: p.labelName,
              labelTitle: p.labelTitle,
              phoneFromLabel: p.phoneFromLabel,
              baseUrl: cfg.baseUrl,
              locale: cfg.locale,
              institutionName: cfg.institutionName,
              institutionType: cfg.institutionType,
              institutionPublicUrl: cfg.institutionPublicUrl,
              combinedParam: cfg.combinedParam,
              perRequestTimeoutMs: cfg.perRequestTimeoutMs,
              concurrency: cfg.concurrency
            });
          }
        }
      } else if (looksLikePerson) {
        const href = extractHref(it.label || "");
        if (href) {
          const persons = parseLabelNames(it.label || "");
          for (const p of persons) {
            personJobs.push({
              personUrl: absolutize(baseUrl, href),
              department: entry.selfLabel,
              topLevel: thisTop,
              labelName: p.labelName,
              labelTitle: p.labelTitle,
              phoneFromLabel: p.phoneFromLabel,
              baseUrl: cfg.baseUrl,
              locale: cfg.locale,
              institutionName: cfg.institutionName,
              institutionType: cfg.institutionType,
              institutionPublicUrl: cfg.institutionPublicUrl,
              combinedParam: cfg.combinedParam,
              perRequestTimeoutMs: cfg.perRequestTimeoutMs,
              concurrency: cfg.concurrency
            });
          }
        }
      } else {
        const nextUrl = absolutize(baseUrl, it && it.io);
        if (nextUrl && !seen[nextUrl]) {
          nextLevel.push({ url: nextUrl, selfLabel: label, topLevel: thisTop, depth: nextDepth });
        }
      }
    }
  }
  currentLevel = nextLevel;
}

if (!personJobs.length) {
  throw new Error("Org tree crawl returned 0 people. Check startUrl / network.");
}

return personJobs.map(j => ({ json: j }));

} // end main
return await main();

async function main() {

function stripHtml(html) {
  return (html || "")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<[^>]*>/g, " ")
    .replace(/&nbsp;|&#160;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, " ")
    .trim();
}

function extractEntityIdFromPersonUrl(url) {
  const m = (url || "").match(/\/person\/-\/person\/([^/]+)\/([^/?#]+)/i);
  return m ? `${m[1]}/${m[2]}` : "";
}

function enc(v) { return encodeURIComponent(v == null ? "" : String(v)); }

function buildVcardUrl(baseUrl, entityId, lang) {
  const l = (lang || "en").toLowerCase();
  const qp = [
    ["_eu_europa_publications_portlet_wiw_entitydetailactions_EntityDetailActionsPortlet_actionName", "downloadVcardAction"],
    ["_eu_europa_publications_portlet_wiw_entitydetailactions_EntityDetailActionsPortlet_displayContextParam", "PERSON"],
    ["_eu_europa_publications_portlet_wiw_entitydetailactions_EntityDetailActionsPortlet_entityId", entityId],
    ["_eu_europa_publications_portlet_wiw_entitydetailactions_EntityDetailActionsPortlet_language", l],
    ["_eu_europa_publications_portlet_wiw_entitydetailactions_EntityDetailActionsPortlet_wiwEntityIdParam", entityId],
    ["p_p_id", "eu_europa_publications_portlet_wiw_entitydetailactions_EntityDetailActionsPortlet"],
    ["p_p_lifecycle", "2"],
    ["p_p_state", "exclusive"]
  ].map(([k, v]) => `${enc(k)}=${enc(v)}`).join("&");
  return `${baseUrl}/en/web/who-is-who/person?${qp}`;
}

function unfoldVcf(vcf) {
  return String(vcf || "")
    .replace(/\r\n[ \t]/g, "")
    .replace(/\n[ \t]/g, "")
    .trim();
}

function parseEmailFromVcf(vcf) {
  if (!vcf) return "";
  const s = unfoldVcf(vcf);
  const lines = s.split(/\r?\n/);
  for (const line of lines) {
    if (!/^EMAIL/i.test(line)) continue;
    const idx = line.indexOf(":");
    if (idx === -1) continue;
    const val = line.slice(idx + 1).trim();
    if (/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i.test(val)) return val;
  }
  return "";
}

function decodeHtmlEntitiesBasic(s) {
  return String(s || "")
    .replace(/&amp;/g, "&").replace(/&quot;/g, '"').replace(/&#39;/g, "'")
    .replace(/&lt;/g, "<").replace(/&gt;/g, ">").replace(/&nbsp;|&#160;/g, " ");
}

function parseEmailFromHtml(html) {
  if (!html) return "";
  const m1 = String(html).match(/href\s*=\s*(?:"|')?\s*mailto:([^"'\s?>&]+)[^"'\s?>]*/i);
  if (m1 && m1[1]) { try { return decodeURIComponent(m1[1]).trim(); } catch { return String(m1[1]).trim(); } }
  const m2 = String(html).match(/itemprop\s*=\s*["']email["'][^>]*>\s*([^<\s]+@[^<\s]+)\s*</i)
          || String(html).match(/itemprop\s*=\s*["']email["'][^>]*content\s*=\s*["']([^"']+@[^"']+)["']/i);
  if (m2 && m2[1]) return String(m2[1]).trim();
  const m3 = String(html).match(/data-email\s*=\s*["']([^"']+@[^"']+)["']/i);
  if (m3 && m3[1]) return String(m3[1]).trim();
  const text = stripHtml(decodeHtmlEntitiesBasic(html));
  const m4 = text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return m4 ? m4[0].trim() : "";
}

function cleanEmpty(val) {
  if (val === null || val === undefined) return "";
  const s = String(val).trim();
  return s.toLowerCase() === "empty" ? "" : s;
}

const TITLE_RE = new RegExp(
  '(?:President of the European Commission|Executive Vice-President|Vice-President of the European Commission|' +
  'High Representative for Foreign Affairs and Security Policy|High Representative|Commissioner for|Commissioner|' +
  'Secretary-General|Deputy Secretary-General|Director-General|Deputy Director-General|' +
  'Director of Office|Head of the Private Office|Head of Unit|Head of Office|Head of sector|' +
  'Head of Division|Head of Cabinet|Head of Department|Head of Programme|Head of Task Force|' +
  'Head of Administration|Head of Projects|Head of Strategy|Head of Resource|' +
  'Deputy Head of Unit|Deputy Head of Division|' +
  'Chief Executive Officer|Chief Operating Officer|Chief Financial Officer|' +
  'Chief Risk Officer|Chief Compliance Officer|Chief|' +
  'Managing Director|Deputy Managing Director|' +
  'Principal Legal Adviser|Acting Principal Legal Adviser|Legal Adviser|Principal|Acting|' +
  'Digital Transformation Officer|Acting Director|Acting Head|' +
  'Vice-President|President|Chair of|Chairperson|Chair|' +
  'Senior Adviser|Senior Manager|Senior Officer|Senior Expert|' +
  'Adviser|Advisor|Administrator|Coordinator|Manager|Expert|Director|Officer|' +
  'Deputy Director|Deputy Chair|Deputy|Member of Cabinet|Member|Head' +
  ')\\b', 'i'
);

function determineFunctionType(level) {
  const t = (level || "").toLowerCase();
  if (t.includes("commissioner") || t.includes("vice-president") || t.includes("vice president") || t.includes("president of the european")) {
    return "Commissioner";
  }
  return "EC civil servant";
}

function splitNameAndLevel(nameRaw, existingLevel) {
  if (existingLevel && existingLevel.trim())
    return { name: (nameRaw || "").trim(), level: existingLevel.trim() };
  const s = (nameRaw || "").trim();
  const m = s.match(TITLE_RE);
  if (m && m.index > 0)
    return { name: s.slice(0, m.index).trim().replace(/,\s*$/, ""), level: s.slice(m.index).trim() };
  return { name: s, level: "" };
}

function safeTextBetween(html, re) {
  const m = (html || "").match(re);
  return m ? stripHtml(m[1]) : "";
}

function extractDdByDt(html, dtLabel) {
  const safe = dtLabel.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const re = new RegExp(`<dt[^>]*>\\s*${safe}\\s*<\/dt>\\s*<dd[^>]*>([\\s\\S]*?)<\/dd>`, "i");
  const m = (html || "").match(re);
  return m ? stripHtml(m[1]) : "";
}

function extractDGFromText(text) {
  const t = (text || "").trim();
  if (!t) return "";
  if (/college of commissioners/i.test(t)) return "College of Commissioners";
  if (/\bcabinets?\b/i.test(t)) return "Cabinets";
  let m = t.match(/\((COM_[A-Z0-9_]+)\)/i);
  if (m) {
    const code = m[1].toUpperCase();
    if (code === "COM_COLL") return "College of Commissioners";
    if (code.includes("CAB")) return "Cabinets";
    return code.replace(/^COM_/, "");
  }
  m = t.match(/\(DG\s*([^)]+)\)/i);
  if (m) return `DG ${m[1].trim()}`;
  m = t.match(/\bDG\s+([A-Z0-9][A-Z0-9 _-]{1,})\b/i);
  if (m) return `DG ${m[1].trim()}`;
  m = t.match(/\bDirectorate-General\s+for\s+([A-Za-z\xC0-\xFF0-9 ,.'\-]+)/i);
  if (m) return `Directorate-General for ${m[1].trim()}`;
  m = t.match(/\b(EMPL|COMP|SANTE|HR|IAS|PMO|TRADE|ENER|MOVE|EAC|BUDG|FISMA|GROW|HOME|JUST|MARE|NEAR|REGIO|RTD|SG|CLIMA|ENV|DIGIT|DEFIS|ECHO|JRC|COMM|CNECT)\b/i);
  if (m) return m[1].toUpperCase();
  return "";
}

function countryFromAffiliation(aff, htmlText) {
  const a = stripHtml(aff || ""), t = stripHtml(htmlText || "");
  let m = a.match(/\bAffiliation\b[:\s-]*([A-Za-z\xC0-\xFF .'\-]{3,})/i)
       || t.match(/\bAffiliation\b[:\s-]*([A-Za-z\xC0-\xFF .'\-]{3,})/i)
       || a.match(/\bNationality\b[:\s-]*([A-Za-z\xC0-\xFF .'\-]{3,})/i)
       || t.match(/\bNationality\b[:\s-]*([A-Za-z\xC0-\xFF .'\-]{3,})/i);
  if (m) return m[1].trim();
  if (a && a.length <= 40 && /^[A-Za-z\xC0-\xFF .'\-]+$/.test(a)) return a.trim();
  return "";
}

function countryFromAddress(addressText) {
  const m = stripHtml(addressText || "").match(/\(([^()]{3,60})\)\s*$/);
  return m ? m[1].trim() : "";
}

function extractCountryFromLeftCard(html) {
  if (!html) return "";
  const m = html.match(/Headshot of[^<]*<\/[^>]+>\s*<[^>]*>\s*([A-Z][A-Za-z\xC0-\xFF' \-]{2,60})\s*</i);
  if (m) return stripHtml(m[1]).trim();
  const m2 = html.match(/Headshot of[\s\S]{0,300}?\b([A-Z][A-Za-z\xC0-\xFF' \-]{2,60})\b\s*</i);
  return m2 ? stripHtml(m2[1]).trim() : "";
}

function countryFromHeader(html) {
  if (!html) return "";
  const m = html.match(/class="[^"]*(?:country|nationality)[^"]*"[^>]*>\s*([^<]{2,60})\s*</i);
  return m ? stripHtml(m[1]).trim() : "";
}

function extractCategory2FromHtml(html) {
  if (!html) return "";
  for (const label of ["Policy area","Policy areas","Areas of responsibility","Area of responsibility","Portfolio","Domain"]) {
    const r = new RegExp(`<dt[^>]*>\\s*${label.replace(/[.*+?^${}()|[\\]\\\\]/g,"\\$&")}\\s*<\/dt>\\s*<dd[^>]*>([\\s\\S]*?)<\/dd>`,"i");
    const m = html.match(r);
    if (m) {
      const dd = m[1] || "";
      const items = [...dd.matchAll(/<li[^>]*>([\s\S]*?)<\/li>/gi)].map(x => stripHtml(x[1])).filter(Boolean);
      if (items.length) return items.join(", ");
      const links = [...dd.matchAll(/<a[^>]*>([\s\S]*?)<\/a>/gi)].map(x => stripHtml(x[1])).filter(Boolean);
      if (links.length) return links.join(", ");
      return stripHtml(dd);
    }
  }
  return "";
}

function extractHierarchyFromHtml(html) {
  const m = (html || "").match(/id="firstPosition"[\s\S]*?<\/div>/i)
         || (html || "").match(/id="positions"[\s\S]*?<\/div>/i)
         || (html || "").match(/class="[^"]*position[^"]*"[\s\S]*?<\/div>/i);
  if (!m) return [];
  return [...m[0].matchAll(/<a[^>]*>([\s\S]*?)<\/a>/gi)]
    .map(x => stripHtml(x[1]))
    .filter(Boolean)
    .filter(t => t.toUpperCase() !== "FORMER");
}

async function httpGet(url, timeout) {
  return await helpers.httpRequest({
    method: "GET", url, timeout: timeout || 40000, json: false,
    headers: { "User-Agent": "Mozilla/5.0", "accept": "text/html, text/plain, */*" }
  });
}

async function mapPool(items, concurrency, worker) {
  const results = new Array(items.length);
  let idx = 0;
  async function runner() {
    while (true) {
      const i = idx++;
      if (i >= items.length) break;
      try { results[i] = await worker(items[i], i); } catch { results[i] = null; }
    }
  }
  const n = Math.max(1, Math.min(concurrency, items.length));
  await Promise.all(Array.from({ length: n }, () => runner()));
  return results;
}

const allItems = $input.all();
const cfg = allItems[0].json;
const baseUrl = cfg.baseUrl || "https://op.europa.eu";
const locale = (cfg.locale || "en").toLowerCase();
const timeoutMs = Number(cfg.perRequestTimeoutMs || 40000);
const concurrency = Number(cfg.concurrency || 9);
const personJobs = allItems.map(i => i.json);

const results = await mapPool(personJobs, concurrency, async (job) => {
  const personUrl = job.personUrl;
  const externalId = extractEntityIdFromPersonUrl(personUrl);
  let html = "";
  try { html = await httpGet(personUrl, timeoutMs); } catch {}

  // Email: HTML first, then vCard
  let email = parseEmailFromHtml(html) || "";
  if (!email && externalId) {
    try { email = parseEmailFromVcf(await httpGet(buildVcardUrl(baseUrl, externalId, locale), timeoutMs)) || ""; } catch {}
    if (!email && locale !== "en") {
      try { email = parseEmailFromVcf(await httpGet(buildVcardUrl(baseUrl, externalId, "en"), timeoutMs)) || ""; } catch {}
    }
  }

  const jobTitle = safeTextBetween(html, /itemprop="jobTitle"[^>]*>([\s\S]*?)<\/span>/i)
                || safeTextBetween(html, /itemprop="jobTitle"[^>]*>([\s\S]*?)<\/div>/i);
  const phone = safeTextBetween(html, /itemprop="telephone"[^>]*>([\s\S]*?)<\/div>/i);
  const affiliation = safeTextBetween(html, /id="affiliation"[^>]*>([\s\S]*?)<\/div>/i);
  const address = safeTextBetween(html, /class="address-addresses[\s\S]*?section"[^>]*>([\s\S]*?)<\/div>/i);
  const affiliationDl = extractDdByDt(html, "Affiliation") || extractDdByDt(html, "Nationality");
  const hierarchy = extractHierarchyFromHtml(html);
  let directBoss = "";
  for (let i = hierarchy.length - 1; i >= 0; i--) {
    if (hierarchy[i] && hierarchy[i].trim()) { directBoss = hierarchy[i].trim(); break; }
  }
  const levelFromDl = extractDdByDt(html, "Position") || extractDdByDt(html, "Function") || extractDdByDt(html, "Job title");
  const split = splitNameAndLevel(job.labelName || "", jobTitle || job.labelTitle || "");
  const finalName = cleanEmpty(split.name.replace(/^(Ms|Mr|Mrs|Dr)\.?\s+/i, "").replace(/\s{2,}/g, " ").trim());
  const finalLevel = cleanEmpty(split.level || levelFromDl);
  const department = cleanEmpty(job.department);
  const finalPhone = phone.trim() || (job.phoneFromLabel || "");
  const ft = determineFunctionType(finalLevel);

  // DG from topLevel (never from person page to avoid name contamination)
  const dgCandidate = cleanEmpty(job.topLevel);
  const dg = TITLE_RE.test(dgCandidate) || /\b(Ms|Mr|Mrs|Dr)\b/i.test(dgCandidate) ? "" : (extractDGFromText(dgCandidate) || dgCandidate);

  const country = extractCountryFromLeftCard(html) || countryFromAddress(address) || countryFromAffiliation(affiliation || affiliationDl, html) || countryFromHeader(html) || "";

  return {
    ExternalId: cleanEmpty(externalId),
    FunctionType: ft,
    Individual_ID_EUmatrix: cleanEmpty(externalId),
    AccessibilityType: "premium",
    Name: finalName,
    Role: ft,
    Level: finalLevel,
    "Direct boss": cleanEmpty(directBoss),
    Department: department,
    DG: cleanEmpty(dg),
    Institution: cleanEmpty(cfg.institutionName),
    "Institution URL": cleanEmpty(cfg.institutionPublicUrl || `${baseUrl}/en/web/who-is-who/organization/-/organization/${cfg.combinedParam || ""}`),
    Country: cleanEmpty(country),
    Party: "",
    "Party ExternalId": "",
    "Political group": "",
    "Political group ExternalId": "",
    "Political / Administrative": ft === "Commissioner" ? "Political" : "Administrative",
    Email: cleanEmpty(email),
    Phone: finalPhone ? ("'" + finalPhone) : "",
    "Category 1": "", "Category ID1": "",
    "Category 2": cleanEmpty(extractCategory2FromHtml(html)), "Category ID2": "",
    "Category 3": "", "Category ID3": "",
    "Category 4": "", "Category ID4": "",
    "Category 5": "", "Category ID5": "",
    "Profile URL": cleanEmpty(personUrl)
  };
});

const rows = results.filter(Boolean);
return rows.map(r => ({ json: r }));

} // end main
return await main();

const SNAPSHOT_NODE = "Loop Over Items";
const HISTORY_NODE  = "Read History";
function norm(v) { return String(v ?? "").trim().toLowerCase().replace(/\s+/g, " "); }
function normPhone(v) {
  const s = String(v ?? "").trim(); if (!s) return "";
  let c = s.replace(/[^\d+]/g, ""); c = c.replace(/^\+{2,}/, "+"); return c;
